#include <string>
#include <algorithm>
#include <iostream>

using namespace std;

/**
 * @brief Checks if a number n is "valid" based on the digit x.
 * 
 * A number is valid if:
 * 1. It contains at least one digit x.
 * 2. It does not start with the digit x.
 * 
 * @param n The input integer.
 * @param x The target digit.
 * @return true if n is valid, false otherwise.
 */
bool solve(long long n, long long x) {
    if (n < 0) {
        // Based on constraints 0 <= n <= 10^5, this case shouldn't happen, 
        // but handling it robustly.
        return false;
    }

    string s = to_string(n);
    char target_char = x + '0';

    // Condition 2: It does not start with the digit x.
    if (s[0] == target_char) {
        return false;
    }

    // Condition 1: It contains at least one digit x.
    // std::string::find returns std::string::npos if the substring is not found.
    if (s.find(target_char) == string::npos) {
        return false;
    }

    // If both conditions are met
    return true;
}

